def BetweenDateHoursLeftInclusive(TestDate: Int, TestHour: Int, StartDate: Int, StartHour: Int, EndDate: Int, EndHour: Int) -> Bool:
    var TestRatioOfDay = TestHour / 24.0
    var StartRatioOfDay = StartHour / 24.0
    var EndRatioOfDay = EndHour / 24.0

    if (StartDate + StartRatioOfDay) <= (EndDate + EndRatioOfDay):
        return (StartDate + StartRatioOfDay) <= TestDate + TestRatioOfDay and TestDate + TestRatioOfDay <= EndDate + EndRatioOfDay
    elif (EndDate + EndRatioOfDay) <= (TestDate + TestRatioOfDay):
        return (EndDate + EndRatioOfDay) <= TestDate + TestRatioOfDay and TestDate + TestRatioOfDay <= StartDate + StartRatioOfDay

def CalcAwbiHattonHeatedFloor(DeltaTemp: Float64, HydraulicDiameter: Float64) -> Float64:
    if HydraulicDiameter > 1.0:
        return 2.175 * math.pow(abs(DeltaTemp), 0.308) / math.pow(HydraulicDiameter, 0.076)
    var pow_fac = 2.175 / math.pow(1.0, 0.076)
    return pow_fac * math.pow(abs(DeltaTemp), 0.308)

def CalcWindSurfaceTheta(WindDir: Float64, SurfAzimuth: Float64) -> Float64:
    var windDir = WindDir % 360
    var surfAzi = SurfAzimuth % 360
    var theta = abs(windDir - surfAzi)
    if theta > 180:
        return abs(theta - 360)
    return theta

def CalcEmmelRoof(WindAt10m: Float64, WindDir: Float64, LongAxisOutwardAzimuth: Float64) -> Float64:
    var Theta = CalcWindSurfaceTheta(WindDir, LongAxisOutwardAzimuth)
    if Theta <= 22.5:
        return 5.11 * WindAt10m ** 0.78
    elif Theta <= 67.5:
        return 4.60 * WindAt10m ** 0.79
    elif Theta <= 112.5:
        return 3.67 * WindAt10m ** 0.85
    elif Theta <= 157.5:
        return 4.60 * WindAt10m ** 0.79
    else:
        return 5.11 * WindAt10m ** 0.78

def FanSpdResidualCool(FanSpdRto: Float64, QCoilSenCoolingLoad: Float64, Ts_1: Float64, Tin: Float64, Garate: Float64, BF: Float64) -> Float64:
    var ZnSenLoad: Float64 = QCoilSenCoolingLoad
    if abs(ZnSenLoad) < 100.0:
        ZnSenLoad = sign(100.0, ZnSenLoad)
    var Tout: Float64 = Tin - (Tin - Ts_1) * (1 - BF)
    var TotCap: Float64 = FanSpdRto * Garate * 1005.0 * (Tin - Tout)
    return TotCap - ZnSenLoad / ZnSenLoad

def HRadPar(T1: Float64, T2: Float64, E1: Float64, E2: Float64) -> Float64:
    var DV: Float64 = 1.0 / E1 + 1.0 / E2 - 1.0
    if E1 > 0.001 and E2 > 0.001:
        var HRadPar: Float64 = (Constant.STEFANBOULTTARFORSTELLENS_CONSTANT / DV) * (T1 + T2) * (T1 ** 2 + T2 ** 2)
    else:
        HRadPar = 0.0
    return HRadPar

def PsyTdbFnHW(H: Float64, dW: Float64) -> Float64:
    var W = max(dW, 1e-5)
    return (H - 2.50094e6 * W) / (1.00484e3 + 1.85895e3 * W)

def RhoH2O(TB: Float64) -> Float64:
    var rho = 1000.1207 + 8.3215874e-04 * TB - 4.929976e-03 * pow_2(TB) + 8.4791863e-06 * pow_3(TB)
    return rho

def SandiaModuleTemperature(Ibc: Float64, Idc: Float64, Ws: Float64, Ta: Float64, fd: Float64, a: Float64) -> Float64:
    var E: Float64 = Ibc + fd * Idc
    return E * exp(a + b * Ws) + Ta

